const items = $input.all();
let allJobs = [];

for (const item of items) {
  const d = item.json;

  if (d.data && Array.isArray(d.data)) {
    for (const j of d.data) {
      allJobs.push({
        job_id:      'jsearch_' + j.job_id,
        title:       j.job_title || '',
        company:     j.employer_name || '',
        location:    j.job_is_remote ? 'Remote' : `${j.job_city||''} ${j.job_country||''}`.trim(),
        is_remote:   j.job_is_remote === true,
        apply_url:   j.job_apply_link || '',
        description: (j.job_description || '').substring(0, 3000),
        salary_min:  j.job_min_salary || null,
        salary_max:  j.job_max_salary || null,
        salary_text: '',
        posted_date: j.job_posted_at_timestamp
          ? new Date(j.job_posted_at_timestamp * 1000).toISOString().split('T')[0] : '',
        source: 'JSearch'
      });
    }
  }
  else if (d.results && Array.isArray(d.results) && typeof d.count === 'number') {
    for (const j of d.results) {
      allJobs.push({
        job_id:      'adzuna_' + (j.id || Math.random().toString(36).substr(2,9)),
        title:       j.title || '',
        company:     (j.company && j.company.display_name) || '',
        location:    (j.location && j.location.display_name) || '',
        is_remote:   ((j.title||'') + ' ' + (j.description||'')).toLowerCase().includes('remote'),
        apply_url:   j.redirect_url || '',
        description: (j.description || '').substring(0, 3000),
        salary_min:  j.salary_min || null,
        salary_max:  j.salary_max || null,
        salary_text: '',
        posted_date: j.created ? j.created.split('T')[0] : '',
        source: 'Adzuna'
      });
    }
  }
  else if (d.results && Array.isArray(d.results) && typeof d.page === 'number') {
    for (const j of d.results) {
      if (!j.name) continue;
      allJobs.push({
        job_id:      'muse_' + (j.id || Math.random().toString(36).substr(2,9)),
        title:       j.name || '',
        company:     (j.company && j.company.name) || '',
        location:    'Remote',
        is_remote:   true,
        apply_url:   (j.refs && j.refs.landing_page) || '',
        description: (j.contents || '').replace(/<[^>]*>/g, '').substring(0, 3000),
        salary_min:  null,
        salary_max:  null,
        salary_text: '',
        posted_date: j.publication_date ? j.publication_date.split('T')[0] : '',
        source: 'TheMuse'
      });
    }
  }
  else if (d.jobs && Array.isArray(d.jobs)) {
    for (const j of d.jobs) {
      allJobs.push({
        job_id:      'remotive_' + (j.id || Math.random().toString(36).substr(2,9)),
        title:       j.title || '',
        company:     j.company_name || '',
        location:    j.candidate_required_location || 'Remote',
        is_remote:   true,
        apply_url:   j.url || '',
        description: (j.description || '').replace(/<[^>]*>/g, '').substring(0, 3000),
        salary_min:  null,
        salary_max:  null,
        salary_text: j.salary || '',
        posted_date: j.publication_date ? j.publication_date.split('T')[0] : '',
        source: 'Remotive'
      });
    }
  }
  else if (d.hits && Array.isArray(d.hits)) {
    for (const j of d.hits) {
      allJobs.push({
        job_id:      'indeed_' + (j.id || Math.random().toString(36).substr(2,9)),
        title:       j.title || '',
        company:     j.company || '',
        location:    (j.location||'').toLowerCase().includes('remote') ? 'Remote' : (j.location || ''),
        is_remote:   (j.location||'').toLowerCase().includes('remote')
                  || ((j.title||'') + ' ' + (j.description||j.summary||'')).toLowerCase().includes('remote'),
        apply_url:   j.url || j.link || '',
        description: (j.description || j.summary || j.snippet || '').substring(0, 3000),
        salary_min:  null,
        salary_max:  null,
        salary_text: j.salary || '',
        posted_date: j.date || j.datePosted || '',
        source: 'Indeed'
      });
    }
  }
  else if (Array.isArray(d)) {
    for (const j of d.slice(1)) {
      if (!j || !j.position) continue;
      allJobs.push({
        job_id:      'remoteok_' + (j.id || Math.random().toString(36).substr(2,9)),
        title:       j.position || '',
        company:     j.company || '',
        location:    'Remote',
        is_remote:   true,
        apply_url:   j.apply_url || j.url || '',
        description: (j.description || '').replace(/<[^>]*>/g, '').substring(0, 3000),
        salary_min:  j.salary_min ? parseInt(j.salary_min) : null,
        salary_max:  j.salary_max ? parseInt(j.salary_max) : null,
        salary_text: '',
        posted_date: j.date ? j.date.split('T')[0] : '',
        source: 'RemoteOK'
      });
    }
  }
}

// Remote-only filter
allJobs = allJobs.filter(j =>
  j.is_remote || j.location.toLowerCase().includes('remote')
);

// Hard exclusions — drop obvious software/web dev roles
// NOTE: 'staff software engineer' and 'principal software' excluded, but NOT plain 'staff engineer'
const DEV_TITLES = [
  'software engineer','software developer','software development',
  'web developer','web engineer','frontend','front-end','back-end','backend',
  'full stack','fullstack','full-stack',
  'mobile developer','ios developer','android developer',
  'data engineer','data scientist','ml engineer','machine learning',
  'application developer','application engineer',
  'java developer','python developer','ruby developer','rails developer',
  'react engineer','angular engineer','ui engineer','ux engineer',
  'staff software engineer','principal software',
];
allJobs = allJobs.filter(j => {
  const title = j.title.toLowerCase();
  return !DEV_TITLES.some(kw => title.includes(kw));
});

// Title must signal infra/ops/network — expanded for polymath roles
const TITLE_OK = [
  'sre','site reliability','reliability engineer',
  'network engineer','network architect','network administrator','network operations',
  'infrastructure engineer','infrastructure architect',
  'platform engineer','cloud engineer','cloud network',
  'devops','dev ops','systems engineer','systems administrator','sysadmin',
  'noc engineer','network security engineer','security engineer',
  'it engineer','it infrastructure','senior it',
  'staff engineer',
  'principal engineer',
  'lead engineer',
  'senior engineer',
];
allJobs = allJobs.filter(j => {
  const title = j.title.toLowerCase();
  return TITLE_OK.some(kw => title.includes(kw));
});

// Exclusion keywords
const EXCL = [
  'clearance required','requires clearance','must have clearance','active secret',
  'top secret','ts/sci','secret clearance','drug test','drug screen',
  'pre-employment drug','drug free workplace required'
];
allJobs = allJobs.filter(j => {
  const txt = (j.title + ' ' + j.description + ' ' + j.company).toLowerCase();
  return !EXCL.some(kw => txt.includes(kw));
});

// Skip jobs where writing app code is the PRIMARY responsibility
const CODE_PRIMARY = [
  'building scalable web application','develop backend service',
  'full-stack development','experience with react is required',
  'ruby on rails','django framework','.net development','java spring boot',
  'mobile application development','design and develop software product',
  'software development lifecycle is your','you will write and maintain code',
];
allJobs = allJobs.filter(j => {
  const descTop = j.description.toLowerCase().substring(0, 1000);
  return !CODE_PRIMARY.some(kw => descTop.includes(kw));
});

// Defense contractor exclusions
const DEFENSE = [
  'lockheed martin','raytheon','northrop grumman','booz allen',
  'general dynamics','l3harris','bae systems','leidos'
];
allJobs = allJobs.filter(j =>
  !DEFENSE.some(c => j.company.toLowerCase().includes(c))
);

// Dedup — dream scout has its own seen list, separate from daily scout
const sd = $getWorkflowStaticData('global');
if (!sd.seenJobIds) sd.seenJobIds = {};
const cutoff = Date.now() - 30 * 24 * 60 * 60 * 1000;
for (const id of Object.keys(sd.seenJobIds)) {
  if (sd.seenJobIds[id] < cutoff) delete sd.seenJobIds[id];
}
const newJobs = allJobs.filter(j => !sd.seenJobIds[j.job_id]);
for (const j of newJobs) sd.seenJobIds[j.job_id] = Date.now();

const limited = newJobs.slice(0, 30);
return [{ json: { jobs: limited, count: limited.length } }];

const resp = $input.first().json;
const { jobs } = $('Format Dream Prompt').first().json;

if (!jobs || jobs.length === 0) {
  return [{ json: { noJobs: true, message: 'No new jobs this run.' } }];
}

let scores = [];
try {
  const raw = resp.candidates[0].content.parts[0].text;
  const cleaned = raw.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  scores = JSON.parse(cleaned);
} catch(e) {
  return [{ json: { noJobs: true, message: 'Score parse error — check Claude response in logs.' } }];
}

// DREAM THRESHOLD: only 80+ earns an alert
const dreamJobs = jobs
  .map((job, i) => {
    const s = scores.find(x => x.index === i + 1);
    if (!s) return null;
    return {
      ...job,
      score:             s.score,
      candidate_fit:     s.candidate_fit || 0,
      dream_fit:         s.dream_fit || 0,
      fit_summary:       s.fit_summary || '',
      dream_highlights:  Array.isArray(s.dream_highlights) ? s.dream_highlights : [],
      missing_skills:    s.missing_skills || 'None',
      red_flags:         s.red_flags || 'None',
      tags:              Array.isArray(s.tags) ? s.tags : [],
      role_type:         s.role_type || 'Infrastructure Engineer',
      resume_tips:       Array.isArray(s.resume_tips) ? s.resume_tips : [s.resume_tips || ''],
      cover_letter_hook: s.cover_letter_hook || ''
    };
  })
  .filter(j => j && j.score >= 80);

if (dreamJobs.length === 0) {
  return [{ json: { noJobs: true, message: `Evaluated ${jobs.length} jobs — none cleared the 80+ dream threshold.` } }];
}

return dreamJobs.map(j => ({ json: j }));

const j = $json;
if (!j.title) return [];

const today = new Date().toISOString().split('T')[0];

function descBlocks(text) {
  const blocks = [];
  const safe = (text || '').substring(0, 9500);
  if (!safe) return [{object:'block',type:'paragraph',paragraph:{rich_text:[{type:'text',text:{content:'(no description available)'}}]}}];
  for (let i = 0; i < safe.length; i += 1900) {
    blocks.push({object:'block',type:'paragraph',paragraph:{rich_text:[{type:'text',text:{content:safe.substring(i, i+1900)}}]}});
  }
  return blocks;
}
function h2(text) {
  return {object:'block',type:'heading_2',heading_2:{rich_text:[{type:'text',text:{content:text}}]}};
}
function divider() { return {object:'block',type:'divider',divider:{}}; }
function bullet(text) {
  return {object:'block',type:'bulleted_list_item',bulleted_list_item:{rich_text:[{type:'text',text:{content:text.substring(0,2000)}}]}};
}
function para(text) {
  return {object:'block',type:'paragraph',paragraph:{rich_text:[{type:'text',text:{content:(text||'').substring(0,2000)}}]}};
}

const highlights = Array.isArray(j.dream_highlights) ? j.dream_highlights.filter(h => h) : [];
const tips = Array.isArray(j.resume_tips) ? j.resume_tips.filter(t => t && t !== 'None') : [];

const children = [
  {
    object: 'block', type: 'callout',
    callout: {
      rich_text: [{type:'text',text:{content:`Dream Job — Score: ${j.score}/100  (Fit: ${j.candidate_fit}/50  |  Dream: ${j.dream_fit}/50)`}}],
      icon: {emoji: '\u2B50'},
      color: 'yellow_background'
    }
  },
  divider(),
  h2('\u2728 Dream Job Signals'),
  ...(highlights.length > 0 ? highlights.map(h => bullet(h)) : [para('No specific dream signals noted.')]),
  divider(),
  h2('\uD83D\uDCCB Full Job Description'),
  ...descBlocks(j.description),
  divider(),
  h2('\uD83C\uDFAF Resume Customization Tips'),
  ...(tips.length > 0 ? tips.slice(0,8).map(t => bullet(t)) : [para('No specific tips generated.')]),
  divider(),
  h2('\u2709\uFE0F Cover Letter Hook'),
  para(j.cover_letter_hook || 'Not generated.'),
];

const tagsValue = (j.tags || []).slice(0, 10).map(t => ({name: String(t).substring(0,100)}));
const tipsShort = tips.slice(0,3).join(' | ').substring(0,500) || 'None';
const clShort = (j.cover_letter_hook || 'None').substring(0,500);
const highlightsShort = highlights.slice(0,3).join(' | ').substring(0,500) || 'None';

const body = {
  parent: { database_id: "YOUR_NOTION_DATABASE_ID" },
  properties: {
    "Job Title":          { title:        [{ text: { content: (j.title   || '').substring(0,200) } }] },
    "Company":            { rich_text:    [{ text: { content: (j.company || '').substring(0,200) } }] },
    "Source":             { select:       { name: j.source || 'JSearch' } },
    "Apply URL":          { url: j.apply_url || null },
    "Location":           { rich_text:    [{ text: { content: (j.location || '').substring(0,200) } }] },
    "Salary Min":         { number: j.salary_min || null },
    "Salary Max":         { number: j.salary_max || null },
    "Score":              { number: j.score || 0 },
    "Fit Summary":        { rich_text:    [{ text: { content: (j.fit_summary    || '').substring(0,2000) } }] },
    "Missing Skills":     { rich_text:    [{ text: { content: (j.missing_skills || 'None').substring(0,500) } }] },
    "Red Flags":          { rich_text:    [{ text: { content: (j.red_flags      || 'None').substring(0,500) } }] },
    "Tags":               { multi_select: tagsValue },
    "Role Type":          { select:       { name: j.role_type || 'Infrastructure Engineer' } },
    "Priority":           { select:       { name: 'Dream' } },
    "Resume Tips":        { rich_text:    [{ text: { content: tipsShort } }] },
    "Cover Letter Draft": { rich_text:    [{ text: { content: clShort   } }] },
    "Status":             { select:       { name: 'New' } },
    "Date Found":         { date:         { start: today } },
    "Posted Date":        { rich_text:    [{ text: { content: j.posted_date || '' } }] },
    "Job ID":             { rich_text:    [{ text: { content: (j.job_id || '').substring(0,200) } }] },
    "Dream Job":          { checkbox: true }
  },
  children: children
};

return [{ json: { ...j, notionBody: JSON.stringify(body) } }];

const items = $input.all();
const today = new Date().toLocaleDateString('en-US',
  {weekday:'long',year:'numeric',month:'long',day:'numeric'});

function cleanUrl(url) {
  try { return url.split('?')[0]; } catch(e) { return url; }
}

const sorted = [...items].sort((a,b) => b.json.score - a.json.score);

// —— Discord ——
let discord = `\u2B50 **DREAM JOB ALERT** \u2014 ${today}\n`;
discord += `Found **${items.length}** job${items.length === 1 ? '' : 's'} that clear the dream threshold\n\n`;

for (const item of sorted) {
  const j = item.json;
  const sal = j.salary_min
    ? `$${Math.round(j.salary_min/1000)}k\u2013$${Math.round((j.salary_max||j.salary_min)/1000)}k`
    : (j.salary_text || 'Salary not listed');

  discord += `**${j.score}/100** \u2014 **${j.title}** @ **${j.company}**\n`;
  discord += `\uD83D\uDCB0 ${sal} \u00B7 \uD83C\uDFAF Fit: ${j.candidate_fit}/50 \u00B7 \u2728 Dream: ${j.dream_fit}/50\n`;
  discord += `${j.fit_summary}\n`;
  if (j.dream_highlights && j.dream_highlights.length) {
    discord += j.dream_highlights.slice(0,3).map(h => `\u2705 ${h}`).join('\n') + '\n';
  }
  if (j.red_flags && j.red_flags !== 'None') {
    discord += `\uD83D\UDEA9 ${j.red_flags}\n`;
  }
  discord += `\uD83D\uDD17 ${cleanUrl(j.apply_url)}\n\n`;
}
discord += `\uD83D\uDCCB Full resume tips + cover letter hook in email & Notion`;

// —— Email ——
let emailRows = '';
for (const item of sorted) {
  const j = item.json;
  const sal = j.salary_min
    ? '$' + j.salary_min.toLocaleString() + (j.salary_max ? '\u2013$' + j.salary_max.toLocaleString() : '+')
    : (j.salary_text || 'Not listed');

  const tagHtml = j.tags && j.tags.length
    ? '<span style="margin-top:4px;display:block">'
      + j.tags.slice(0,6).map(t => `<span style="background:#fff3cd;color:#856404;padding:2px 6px;border-radius:10px;font-size:11px;margin-right:3px">${t}</span>`).join('')
      + '</span>'
    : '';

  const highlightHtml = j.dream_highlights && j.dream_highlights.length
    ? '<ul style="margin:6px 0 4px 16px;padding:0;color:#155724;font-size:13px">'
      + j.dream_highlights.slice(0,4).map(h => `<li>${h}</li>`).join('')
      + '</ul>'
    : '';

  const tipsHtml = j.resume_tips && j.resume_tips.length
    ? '<div style="margin-top:8px"><strong style="font-size:12px;color:#6c757d">RESUME TIPS:</strong>'
      + '<ul style="margin:4px 0 0 16px;padding:0;font-size:12px;color:#495057">'
      + j.resume_tips.slice(0,4).map(t => `<li>${t}</li>`).join('')
      + '</ul></div>'
    : '';

  const hookHtml = j.cover_letter_hook
    ? `<div style="margin-top:8px;padding:8px;background:#f8f9fa;border-left:3px solid #ffc107;font-size:13px;color:#495057"><strong>Cover letter:</strong> ${j.cover_letter_hook}</div>`
    : '';

  emailRows += `<tr style="border-bottom:2px solid #ffc107">`
    + `<td style="padding:16px;vertical-align:top;width:70px;text-align:center">`
    + `<span style="background:#856404;color:#fff3cd;padding:6px 10px;border-radius:12px;font-weight:bold;font-size:16px">${j.score}</span>`
    + `<br><span style="font-size:11px;color:#aaa;margin-top:4px;display:block">${j.candidate_fit}+${j.dream_fit}</span>`
    + `<br><span style="font-size:10px;color:#aaa">${j.source}</span></td>`
    + `<td style="padding:16px">`
    + `<strong style="font-size:16px"><a href="${j.apply_url}" style="color:#212529;text-decoration:none">${j.title}</a></strong>`
    + ` <span style="font-size:12px;color:#6c757d">@ ${j.company}</span><br>`
    + `<span style="color:#888;font-size:13px">${j.location}</span> &nbsp;|&nbsp; `
    + `<span style="color:#198754;font-size:13px;font-weight:bold">${sal}</span><br>`
    + `<div style="margin:6px 0;font-size:14px;color:#343a40">${j.fit_summary}</div>`
    + tagHtml
    + (highlightHtml ? `<div style="margin-top:6px"><strong style="font-size:12px;color:#155724">\u2728 Dream signals:</strong>${highlightHtml}</div>` : '')
    + (j.red_flags && j.red_flags !== 'None' ? `<div style="color:#dc3545;font-size:12px;margin-top:4px">\uD83D\uDEA9 ${j.red_flags}</div>` : '')
    + tipsHtml
    + hookHtml
    + `<div style="margin-top:6px"><a href="${j.apply_url}" style="color:#0d6efd;font-size:13px">Apply \u2192</a> &nbsp;|&nbsp; <span style="color:#aaa;font-size:12px">Posted: ${j.posted_date||'Unknown'}</span></div>`
    + '</td></tr>';
}

const emailSubject = sorted.length === 1
  ? `\u2B50 Dream Job: ${sorted[0].json.title} @ ${sorted[0].json.company} (${sorted[0].json.score}/100)`
  : `\u2B50 ${sorted.length} Dream Jobs Found \u2014 ${today}`;

const emailHtml = `<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:860px;margin:0 auto;color:#212529">
<div style="background:#ffc107;padding:16px 24px;border-radius:8px 8px 0 0">
  <h2 style="margin:0;color:#212529">\u2B50 Dream Job Alert \u2014 ${today}</h2>
  <p style="margin:4px 0 0;color:#343a40">Found <strong>${sorted.length}</strong> job${sorted.length===1?'':'s'} that clear the 80+ dream threshold. <a href="https://www.notion.so/" style="color:#212529">View in Notion \u2192</a></p>
</div>
<table style="width:100%;border-collapse:collapse;border:1px solid #ffc107">
<tbody>${emailRows}</tbody></table>
<p style="margin-top:16px;color:#6c757d;font-size:12px">
  Dream threshold: 80+/100 \u2014 scored on candidate fit (0\u201350) + dream criteria (0\u201350).
  Daily scout runs at 7AM; Dream Scout at 8AM.
</p>
</body></html>`;

return [{ json: {
  discord_content: discord,
  email_html:      emailHtml,
  email_subject:   emailSubject,
  has_jobs: true
} }];
